  await syncCollection("notes", async () => {
    const [notes, tags, categories] = await Promise.all([
      prisma.note.findMany({
        include: {
          tags: true,
          categories: true,
          relationsFrom: true,
          files: true,
        },
      }),
      prisma.tag.findMany(),
      prisma.category.findMany(),
    ]);
    const tagMap = new Map(tags.map((tag) => [tag.id, tag]));
